# ---- Helper Functions ----

def majority_vote(image_id: str) -> Optional[dict]:
    """Aggregate labels for an image using majority voting."""
    if image_id not in annotation_store or len(annotation_store[image_id]) == 0:
        return None

    annotations = annotation_store[image_id]
    labels = [a["label"] for a in annotations]
    counter = Counter(labels)
    most_common_label, vote_count = counter.most_common(1)[0]
    total_votes = len(labels)
    agreement_ratio = vote_count / total_votes

    result = {
        "label": most_common_label,
        "vote_count": vote_count,
        "total_votes": total_votes,
        "agreement_ratio": round(agreement_ratio, 4),
        "label_distribution": dict(counter),
    }

    aggregated_labels[image_id] = result
    return result


def weighted_majority_vote(image_id: str) -> Optional[dict]:
    """Aggregate labels using confidence-weighted majority voting."""
    if image_id not in annotation_store or len(annotation_store[image_id]) == 0:
        return None

    annotations = annotation_store[image_id]
    weighted_votes: dict = {}

    for a in annotations:
        label = a["label"]
        confidence = a.get("confidence", 1.0)
        weighted_votes[label] = weighted_votes.get(label, 0.0) + confidence

    best_label = max(weighted_votes, key=weighted_votes.get)
    total_weight = sum(weighted_votes.values())

    result = {
        "label": best_label,
        "weighted_score": round(weighted_votes[best_label], 4),
        "total_weight": round(total_weight, 4),
        "agreement_ratio": round(weighted_votes[best_label] / total_weight, 4),
        "weighted_distribution": {k: round(v, 4) for k, v in weighted_votes.items()},
    }

    return result


def get_training_data() -> tuple[list, list]:
    """Get images and their aggregated labels for training."""
    images = []
    labels = []

    for image_id, agg in aggregated_labels.items():
        if image_id in image_store:
            images.append(image_store[image_id]["data"])
            labels.append(agg["label"])

    return images, labels


# ---- PyTorch Dataset and Model ----

if HAS_TORCH and HAS_PIL:

    class LabeledImageDataset(Dataset):
        def __init__(self, image_bytes_list, labels, label_to_idx, transform=None):
            self.image_bytes_list = image_bytes_list
            self.labels = labels
            self.label_to_idx = label_to_idx
            self.transform = transform or transforms.Compose([
                transforms.Resize((224, 224)),
                transforms.ToTensor(),
                transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
            ])

        def __len__(self):
            return len(self.image_bytes_list)

        def __getitem__(self, idx):
            img_bytes = self.image_bytes_list[idx]
            image = Image.open(io.BytesIO(img_bytes)).convert("RGB")
            image = self.transform(image)
            label = self.label_to_idx[self.labels[idx]]
            return image, label

    def build_model(num_classes: int) -> nn.Module:
        model = models.resnet18(weights=None)
        model.fc = nn.Linear(model.fc.in_features, num_classes)
        return model

    def train_model_on_data(image_bytes_list, labels, epochs=10, batch_size=8, lr=0.001):
        """Train a ResNet18 model on the labeled data without validation."""
        unique_labels = sorted(set(labels))
        label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
        idx_to_label = {idx: label for label, idx in label_to_idx.items()}
        num_classes = len(unique_labels)

        dataset = LabeledImageDataset(image_bytes_list, labels, label_to_idx)
        dataloader = DataLoader(dataset, batch_size=batch_size, shuffle=True, num_workers=0)

        device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        model = build_model(num_classes).to(device)
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(model.parameters(), lr=lr)

        model.train()
        total_loss = 0.0
        total_correct = 0
        total_samples = 0

        for epoch in range(epochs):
            epoch_loss = 0.0
            epoch_correct = 0
            epoch_samples = 0

            for batch_images, batch_labels in dataloader:
                batch_images = batch_images.to(device)
                batch_labels = batch_labels.to(device)

                optimizer.zero_grad()
                outputs = model(batch_images)
                loss = criterion(outputs, batch_labels)
                loss.backward()
                optimizer.step()

                epoch_loss += loss.item() * batch_images.size(0)
                _, predicted = torch.max(outputs, 1)
                epoch_correct += (predicted == batch_labels).sum().item()
                epoch_samples += batch_images.size(0)

            total_loss = epoch_loss / epoch_samples
            total_correct = epoch_correct
            total_samples = epoch_samples

        training_accuracy = total_correct / total_samples if total_samples > 0 else 0.0

        return model, label_to_idx, idx_to_label, training_accuracy, total_loss


