@app.get("/annotator/{annotator_id}/stats")
def get_annotator_stats(annotator_id: str):
    if annotator_id not in annotator_store:
        raise HTTPException(status_code=404, detail="Annotator not found")

    # Calculate per-annotator stats
    annotator_annotations = []
    agreement_count = 0
    total_labeled = 0

    for image_id, annotations in annotation_store.items():
        for ann in annotations:
            if ann["annotator_id"] == annotator_id:
                annotator_annotations.append({
                    "image_id": image_id,
                    "label": ann["label"],
                    "confidence": ann["confidence"],
                    "timestamp": ann["timestamp"],
                })
                # Check agreement with majority vote
                if image_id in aggregated_labels:
                    total_labeled += 1
                    if ann["label"] == aggregated_labels[image_id]["label"]:
                        agreement_count += 1

    agreement_rate = agreement_count / total_labeled if total_labeled > 0 else 0.0

    return {
        "annotator": annotator_store[annotator_id],
        "total_annotations": len(annotator_annotations),
        "agreement_with_majority": round(agreement_rate, 4),
        "recent_annotations": annotator_annotations[-10:],
    }


