@app.post("/annotations/submit")
def submit_annotation(submission: AnnotationSubmission):
    if submission.image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found")

    if submission.annotator_id not in annotator_store:
        raise HTTPException(status_code=404, detail="Annotator not found. Please register first.")

    # Check for duplicate annotation (same annotator, same image)
    existing = annotation_store.get(submission.image_id, [])
    for ann in existing:
        if ann["annotator_id"] == submission.annotator_id:
            raise HTTPException(
                status_code=400,
                detail=f"Annotator '{submission.annotator_id}' has already labeled image '{submission.image_id}'"
            )

    # Add label to known classes
    label_classes.add(submission.label)

    annotation = {
        "annotator_id": submission.annotator_id,
        "label": submission.label,
        "confidence": submission.confidence,
        "timestamp": datetime.utcnow().isoformat(),
    }

    annotation_store[submission.image_id].append(annotation)
    annotator_store[submission.annotator_id]["annotations_count"] += 1

    return {
        "message": "Annotation submitted",
        "image_id": submission.image_id,
        "label": submission.label,
        "total_annotations_for_image": len(annotation_store[submission.image_id]),
    }


@app.post("/annotations/batch")
def submit_batch_annotations(batch: BatchAnnotationSubmission):
    results = []
    errors = []

    for submission in batch.annotations:
        try:
            if submission.image_id not in image_store:
                errors.append({"image_id": submission.image_id, "error": "Image not found"})
                continue

            if submission.annotator_id not in annotator_store:
                errors.append({"image_id": submission.image_id, "error": "Annotator not found"})
                continue

            # Check duplicate
            existing = annotation_store.get(submission.image_id, [])
            duplicate = any(a["annotator_id"] == submission.annotator_id for a in existing)
            if duplicate:
                errors.append({
                    "image_id": submission.image_id,
                    "error": f"Duplicate annotation by {submission.annotator_id}"
                })
                continue

            label_classes.add(submission.label)

            annotation = {
                "annotator_id": submission.annotator_id,
                "label": submission.label,
                "confidence": submission.confidence,
                "timestamp": datetime.utcnow().isoformat(),
            }

            if submission.image_id not in annotation_store:
                annotation_store[submission.image_id] = []
            annotation_store[submission.image_id].append(annotation)
            annotator_store[submission.annotator_id]["annotations_count"] += 1

            results.append({"image_id": submission.image_id, "status": "success"})

        except Exception as e:
            errors.append({"image_id": submission.image_id, "error": str(e)})

    return {
        "message": "Batch processing complete",
        "successful": len(results),
        "failed": len(errors),
        "results": results,
        "errors": errors,
    }


