@app.post("/aggregate/{image_id}")
def aggregate_image_labels(image_id: str, method: str = "majority"):
    if image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found")

    if not annotation_store.get(image_id):
        raise HTTPException(status_code=400, detail="No annotations for this image")

    if method == "majority":
        result = majority_vote(image_id)
    elif method == "weighted":
        result = weighted_majority_vote(image_id)
        aggregated_labels[image_id] = result
    else:
        raise HTTPException(status_code=400, detail="Invalid method. Use 'majority' or 'weighted'.")

    return {"image_id": image_id, "method": method, "result": result}


@app.post("/aggregate/all")
def aggregate_all_labels(method: str = "majority", min_annotations: int = 1):
    """Aggregate labels for all images that have at least min_annotations."""
    results = {}
    skipped = []

    for image_id in image_store:
        annotations = annotation_store.get(image_id, [])
        if len(annotations) < min_annotations:
            skipped.append(image_id)
            continue

        if method == "majority":
            result = majority_vote(image_id)
        elif method == "weighted":
            result = weighted_majority_vote(image_id)
            aggregated_labels[image_id] = result
        else:
            raise HTTPException(status_code=400, detail="Invalid method")

        if result:
            results[image_id] = result

    return {
        "message": "Aggregation complete",
        "method": method,
        "aggregated_count": len(results),
        "skipped_count": len(skipped),
        "results": results,
    }


